import React from 'react'
import styled from 'styled-components'

const ProjectCardWrapper = styled.article`
  ${'' /*  */}
  border: 2px solid orange;
  width: 100%;
  padding: 2rem 1rem;
  transition: 0.2s;

  &:hover {
    background: rgba(255, 165, 0, 0.1);
  }

  h3 {
    margin-bottom: 10px;
  }

  .buttons {
    display: grid;
    grid-template-columns: 1fr 1fr;
    grid-gap: 10px;

    a.btn {
      padding: 8px 1rem;
      background: black;
      width: 100%;
      color: #fff;
      text-align: center;
      font-weight: bold;
      transition: 0.2s;
      border-radius: 2px;

      &:hover {
        opacity: 0.8;
      }
    }
  }
`

function ProjectCard(project) {
  return (
    <ProjectCardWrapper>
      <h3>{project.title}</h3>
      <img src={project.imgPath} alt="" />

      <br />
      <div className="buttons">
        <a target="_blank" href={project.codeLink} className="btn">
          GitHub
        </a>
        <a target="_blank" href={project.liveLink} className="btn">
          Demo
        </a>
      </div>
    </ProjectCardWrapper>
  )
}

export default ProjectCard
