import React from 'react'
import styled, { keyframes } from 'styled-components'
import SectionTitleStyle from '../styels/SectionTitleStyle'

const coolAnimation = keyframes`
  0% {
    transform: scale(0.98);
  } 

  100% {
    transform:scale(1);
  }
`

const SkillsWrapper = styled.section`
  padding: 0 0 2rem 0;
  overflow: hidden;
  background: url('img/skills-bg.jpg') rgba(255, 255, 255, 0.9);
  background-position: center;
  background-size: cover;
  background-blend-mode: multiply;
  position: relative;
  z-index: 1;
  margin-top: 20px;

  #skillstitle {
    margin: 2rem 0;
  }

  .overlay {
    position: absolute;
    width: 100%;
    height: 100%;
    background: rgba(0, 0, 0, 0.6);
    z-index: -1;
  }

  .skills {
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    grid-gap: 10px;

    .card {
      border: 3px solid orange;
      display: flex;
      justify-content: center;
      flex-direction: column;
      align-items: center;
      background: orange;
      cursor: pointer;
      border-radius: 4px;
      transition: 0.4s;
      user-select: none;
      padding: 1rem 0;

      &:hover {
        opacity: 0.6;
        animation: ${coolAnimation} 0.5s ease-in-out;
      }
    }
  }

  img {
    width: 100px;
  }
`

function Skills() {
  return (
    <SkillsWrapper id="skills">
      <div className="overlay"></div>
      <div className="container">
        <SectionTitleStyle id="skillstitle">Skills</SectionTitleStyle>
        <div className="skills">
          <div className="card">
            <img src="img/skills/js.png" alt="" />
            <h4>JavaScript</h4>
          </div>
          <div className="card">
            <img src="img/skills/react.svg" alt="" />
            <h4>REACTjs</h4>
          </div>
          <div className="card">
            <img src="img/skills/vuejs.svg" alt="" />
            <h4>VUEjs</h4>
          </div>
          <div className="card">
            <img src="img/skills/node.svg" alt="" />
            <h4>NODEjs</h4>
          </div>
          <div className="card">
            <img src="img/skills/bootstrap.svg" alt="" />
            <h4>Bootstrap</h4>
          </div>
          <div className="card">
            <img src="img/skills/html.svg" alt="" />
            <h4>HTML</h4>
          </div>
          <div className="card">
            <img src="img/skills/css.svg" alt="" />
            <h4>CSS</h4>
          </div>
          <div className="card">
            <img src="img/skills/git.svg" alt="" />
            <h4>Git</h4>
          </div>
          <div className="card">
            <img src="img/skills/github.svg" alt="" />
            <h4>GitHub</h4>
          </div>
          <div className="card">
            <img src="img/skills/mongodb.svg" alt="" />
            <h4>MONGOdb</h4>
          </div>
          <div className="card">
            <img src="img/skills/json.svg" alt="" />
            <h4>JSON</h4>
          </div>
          <div className="card">
            <img src="img/skills/mysql.svg" alt="" />
            <h4>MYsql</h4>
          </div>
        </div>
      </div>
    </SkillsWrapper>
  )
}

export default Skills
