import React from 'react'
import styled, { keyframes } from 'styled-components'

function rotateAnimation() {
  return keyframes`
    0% {
      transform: rotate(0deg);
    }
    100% {
      transform: rotate(360deg);
    }
  `
}

const NavigationWrapper = styled.nav`
  padding: 2rem;
  background: white;
  border-bottom: 6px solid orange;

  .container {
    ul {
      display: grid;
      grid-template-columns: repeat(5, 1fr);

      li {
        list-style: none;
        padding-top: 2px;
        border-bottom: 5px groove transparent;
        transition: 0.4s ease;
        text-align: center;
        margin: 0 10px;

        a {
          font-family: inherit;
          font-size: 1.5rem;
          font-weight: 600;
          z-index: 1;
        }

        img {
          width: 50px;
          position: absolute;
          pointer-events: none;
          margin-left: -10px;
          margin-top: 10px;
        }

        &:hover {
          border-color: orange;

          img {
            animation: ${rotateAnimation} 4s infinite linear;
          }
        }

        &.active {
          border-color: orange;
        }
      }
    }
  }
`

function Navigation() {
  return (
    <NavigationWrapper>
      <div className="container">
        <ul>
          <li>
            <img src="img/link.png" />
            <small>🏠</small>
            <br />
            <a href="#home">Home</a>
          </li>

          <li>
            <img src="img/link.png" />
            <small>👨‍⚖️</small>
            <br />
            <a href="#about">About</a>
          </li>

          <li>
            <img src="img/link.png" />
            <small>🧾</small>
            <br />
            <a href="#skills">Skills</a>
          </li>

          <li>
            <img src="img/link.png" />
            <small>💻</small>
            <br />
            <a href="#projects">Projets</a>
          </li>

          <li id="contact">
            <img src="img/link.png" />
            <small>✉</small>
            <br />
            <a href="#contactSection">Contact</a>
          </li>
        </ul>
      </div>
    </NavigationWrapper>
  )
}

export default Navigation
