import React, { useState } from 'react'
import styled from 'styled-components'
import ProjectCard from '../shared/ProjectCard'
import SectionTitleStyle from '../styels/SectionTitleStyle'

const ProjectsWrapper = styled.section`
  padding: 2rem;

  .projects {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    grid-gap: 20px;
  }
`

function Projects() {
  const [projects, setProjects] = useState([
    {
      id: 1,
      imgPath: '/img/projects/p1.png',
      title: 'Age Calculator',
      codeLink:
        'https://github.com/moniruzzamansaikat/vanilla-js-age-calculator',
      liveLink: 'https://vanilla-js-age-calculator.netlify.app/',
    },
    {
      id: 2,
      imgPath: '/img/projects/p2.png',
      title: 'JS Drum Kit',
      codeLink: 'https://github.com/moniruzzamansaikat/javascript-drum-kit',
      liveLink: 'https://js-drum-kit1.netlify.app/',
    },
    {
      id: 3,
      imgPath: '/img/projects/p3.png',
      title: 'Grocery List',
      codeLink: 'https://github.com/moniruzzamansaikat/vanilla-js-grocery-app',
      liveLink: 'https://vanillajs-grocery-app.netlify.app/',
    },
    {
      id: 4,
      imgPath: '/img/projects/p4.png',
      title: 'Stop Watch',
      codeLink: 'https://github.com/moniruzzamansaikat/vanilla-js-stopwatch',
      liveLink: 'https://vanilla-js-stopwatch.netlify.app/',
    },
    {
      id: 5,
      imgPath: '/img/projects/p5.jpg',
      title: 'Profile Card Component',
      codeLink:
        'https://github.com/moniruzzamansaikat/profile-card-component/tree/master',
      liveLink: 'https://profile-card-component1.netlify.app/',
    },
    {
      id: 6,
      imgPath: '/img/projects/p6.jpg',
      title: 'Faq accordion',
      codeLink: 'https://github.com/moniruzzamansaikat/faq-accordion-card',
      liveLink: 'https://faq-accordion1.netlify.app/',
    },
  ])

  return (
    <ProjectsWrapper id="projects">
      <div className="container">
        <SectionTitleStyle>Projects</SectionTitleStyle>
        <div className="projects">
          {projects.map((project) => (
            <ProjectCard key={project.id} {...project}></ProjectCard>
          ))}
        </div>
      </div>
    </ProjectsWrapper>
  )
}

export default Projects
