import React from 'react'
import styled from 'styled-components'

// style for hero
const HeroWrapper = styled.section`
  background: url('img/header.jpg');
  background-size: cover;
  backgorund-position: center;
  position: relative;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 2rem 1rem;
  border-bottom: 5px solid orange;
  text-align: center;

  ${'' /* overlay */}
  .overlay {
    position: absolute;
    width: 100%;
    height: 100%;
    background: rgba(255, 255, 255, 0.9);
  }

  h1 {
    font-size: 2rem;
    font-family: var(--header-font);
    letter-spacing: 3px;
    font-style: italic;
    font-weight: 900;
    margin-bottom: 2rem;
  }

  h2 {
    line-height: 5rem;
    font-size: 3rem;
    margin-top: 2rem;
    font-style: italic;
    position: relative;
    display: inline;

    .card {
      width: 2.5rem;
      height: 2.5rem;
      background: orange;
      position: absolute;
      top: -15px;
      left: -15px;
    }
  }

  h2 span {
    background: orange;
    padding: 0 1rem;

    ${'' /* color: white; */}
  }

  .container {
    color: black;
    z-index: 1;
    padding: 5rem 0;
  }

  div.intro {
    margin: 2rem;
    font-size: 1.4rem;
    padding: 1rem 0;
    font-family: 'Open Sans';
    font-weight: 600;
  }
`

function Hero() {
  return (
    <HeroWrapper>
      <div className="overlay"></div>
      <div className="container">
        <h1>Hey, I'm Saikat.</h1>
        <h2>
          <span>I am a full stack developer.</span>
          <div className="card"></div>
        </h2>
        <div className="intro">
          <p>I am a fullstack javascript developer</p>
          <br />
          <p>
            I work with latest technology for making awesome <br /> highly
            scalabel web application
          </p>
        </div>
      </div>
    </HeroWrapper>
  )
}

export default Hero
