import React from 'react'
import styled from 'styled-components'

const FooterWrapper = styled.footer`
  ${'' /*  */}
  padding: 2rem 0;

  a {
    transition: 0.56s;

    &:hover {
      transform: scale(1.1);
    }

    img {
      width: 70px;
    }
  }

  ${'' /* make two partials */}
  .container {
    display: grid;
    grid-template-columns: 1fr 1fr;

    .footer-left {
      display: flex;
      justify-content: space-around;
    }

    .footer-right {
      display: flex;
      align-items: center;
      border-left: 4px solid var(--primary-color);

      p {
        margin-left: 40px;
      }
    }
  }
`

function Footer() {
  return (
    <FooterWrapper>
      <div className="container">
        <div className="footer-left">
          <a href="https://twitter.com/m__saikat/" target="_blank">
            <img src="img/social/twitter.png" alt="" />
          </a>
          <a href="https://github.com/moniruzzamansaikat" target="_blank">
            <img src="img/social/github.png" alt="" />
          </a>
          <a
            href="https://facebook.com/moniruzzaman.saikat18?_rdc=1&_rdr"
            target="_blank"
          >
            <img src="img/social/facebook.png" alt="" />
          </a>
          <a
            href="https://www.instagram.com/moniruzzaman.saikat/"
            target="_blank"
          >
            <img src="img/social/instagram.png" alt="" />
          </a>
        </div>
        <div className="footer-right">
          <p>
            Saikat &copy; 2021 | <em>All Right Reserved</em>
          </p>
        </div>
      </div>
    </FooterWrapper>
  )
}

export default Footer
