import React from 'react'
import styled from 'styled-components'

const TopStyle = styled.a`
  font-size: 4rem;
  position: fixed;
  right: 1rem;
  bottom: 4rem;
  z-index: 1000;
`

export default function GoToTop() {
  return (
    <TopStyle>
      <a href="#home">🔝</a>
    </TopStyle>
  )
}
