import React from 'react'
import SectionTitleStyle from '../styels/SectionTitleStyle'
import styled, { keyframes } from 'styled-components'

const ContactWrapper = styled.section`
  padding: 0 0 2rem 0;
  overflow: hidden;
  background: url('img/skills-bg.jpg') rgba(255, 255, 255, 0.9);
  background-position: center;
  background-size: cover;
  background-blend-mode: multiply;
  position: relative;
  z-index: 1;
  margin-top: 20px;

  #title {
    margin-top: 20px;
  }

  .overlay {
    position: absolute;
    width: 100%;
    height: 100%;
    background: rgba(0, 0, 0, 0.6);
    z-index: -1;
  }

  .contact {
    .info-box {
      display: grid;
      grid-template-columns: 1fr 1fr;
      grid-gap: 20px;
      margin: 10px 0;

      input {
        width: 100%;
        padding: 8px 1rem;
        outline: 0;
        border: 0;
        font-family: 'Open Sans', sans-serif;
        font-weight: bold;
        border: 2px solid transparent;
        transition: 0.5s;

        &:focus {
          border: 2px solid var(--primary-color);
        }
      }
    }

    .message-box {
      margin: 20px 0;

      textarea {
        width: 100%;
        border: 0;
        outline: 0;
        height: 5rem;
        padding: 8px 1rem;
        font-family: 'Open Sans', sans-serif;
        font-weight: bold;
        border: 2px solid transparent;
        transition: 0.5s;
        resize: none;

        &:focus {
          border: 2px solid var(--primary-color);
        }
      }
    }

    .button-box {
      button {
        width: 100%;
        padding: 8px 1rem;
        outline: 0;
        border: 0;
        background: var(--primary-color);
        border-radius: 4px;
        cursor: pointer;
        color: #000;
        font-weight: bold;

        &:hover,
        &:focus {
          opacity: 0.7;
        }
      }
    }
  }
`

function Contact() {
  return (
    <ContactWrapper id="contactSection">
      <div className="overlay"></div>
      <div className="container">
        <SectionTitleStyle id="title">Contact</SectionTitleStyle>
        <div className="contact">
          <div className="info-box">
            <input type="text" placeholder="Name" />
            <input type="email" placeholder="Email" />
          </div>
          <div className="message-box">
            <textarea placeholder="Message"></textarea>
          </div>
          <div className="button-box">
            <button>Send</button>
          </div>
        </div>
      </div>
    </ContactWrapper>
  )
}

export default Contact
